 1	import * as React from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getVMIIPAddresses } from '@kubevirt-utils/resources/vmi';
 6	import { Button, ButtonVariant, Popover, PopoverPosition } from '@patternfly/react-core';
 7	
 8	type VirtualMachinesInstancesIPProps = {
 9	  vmi: V1VirtualMachineInstance;
10	};
11	
12	const VirtualMachinesInstancesIP: React.FC<VirtualMachinesInstancesIPProps> = ({ vmi }) => {
13	  const { t } = useKubevirtTranslation();
14	  const ips = getVMIIPAddresses(vmi);
15	
16	  return (
17	    <>
18	      <div>{ips?.[0]}</div>
19	      {ips?.length > 1 && (
20	        <Popover
21	          bodyContent={ips?.map((item) => (
22	            <div key={item}>{item}</div>
23	          ))}
24	          hasAutoWidth
25	          headerContent={t('IP addresses')}
26	          position={PopoverPosition.top}
27	        >
28	          <Button variant={ButtonVariant.link}>{`+${ips?.length - 1} more`}</Button>
29	        </Popover>
30	      )}
31	    </>
32	  );
33	};
34	
35	export default VirtualMachinesInstancesIP;

